{
  "name": "TexRewriter - Chuyển Đổi LaTeX Thông Minh",
  "description": "Ứng dụng sử dụng AI Gemini để chuyển đổi các tệp LaTeX (.tex) phức tạp thành văn bản thuần túy dễ đọc, hỗ trợ tải lên nhiều tệp cùng lúc.",
  "requestFramePermissions": []
}

import { GoogleGenAI } from "@google/genai";

export const rewriteLatexToText = async (latex: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Bạn là một chuyên gia chuyển đổi văn bản. Hãy viết lại nội dung LaTeX sau đây thành văn bản thuần túy (Plain Text) tiếng Việt mạch lạc, dễ đọc.

    Yêu cầu:
    1. Loại bỏ tất cả các lệnh LaTeX (\begin, \section, \textbf, \textit, \usepackage, v.v.).
    2. Bỏ qua phần khai báo (preamble) trước \begin{document} nếu có.
    3. Trình bày nội dung một cách tự nhiên như một bài văn hoặc tài liệu đọc thông thường.
    4. Giữ nguyên ý nghĩa cốt lõi và các thông tin quan trọng.
    5. Các công thức toán học hãy chuyển sang dạng ký hiệu đơn giản dễ đọc trên màn hình điện thoại/máy tính (ví dụ: dùng ^ thay cho số mũ, dùng các ký hiệu Unicode cho các ký tự Hy Lạp).

    Nội dung LaTeX cần chuyển đổi:
    ---
    ${latex}
    ---
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: prompt }] }],
    });

    return response.text || "Không thể tạo nội dung. Vui lòng thử lại.";
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Lỗi khi kết nối với AI Gemini.");
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { rewriteLatexToText } from './services/geminiService';

const App: React.FC = () => {
  const [rawText, setRawText] = useState<string>("");
  const [processedText, setProcessedText] = useState<string>("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [status, setStatus] = useState<{ type: 'ready' | 'success' | 'error' | 'loading', msg: string }>({
    type: 'ready',
    msg: 'Hệ thống sẵn sàng'
  });
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    document.body.setAttribute('data-theme', theme);
  }, [theme]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    setIsProcessing(true);
    setStatus({ type: 'loading', msg: `Đang nạp ${files.length} tệp...` });

    try {
      let combinedText = "";
      for (let i = 0; i < files.length; i++) {
        const text = await files[i].text();
        combinedText += (combinedText ? "\n\n% --- FILE: " + files[i].name + " ---\n" : "") + text;
      }
      setRawText(prev => prev + (prev ? "\n\n" : "") + combinedText);
      setStatus({ type: 'success', msg: `Đã nạp thành công ${files.length} tệp.` });
    } catch (err) {
      setStatus({ type: 'error', msg: "Lỗi khi đọc tệp." });
    } finally {
      setIsProcessing(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleRewrite = async () => {
    if (!rawText.trim()) {
      setStatus({ type: 'error', msg: "Vui lòng nhập nội dung LaTeX!" });
      return;
    }

    setIsProcessing(true);
    setStatus({ type: 'loading', msg: "AI đang phân tích và viết lại..." });

    try {
      const result = await rewriteLatexToText(rawText);
      setProcessedText(result);
      setStatus({ type: 'success', msg: "Đã chuyển đổi thành công!" });
    } catch (err: any) {
      setStatus({ type: 'error', msg: err.message || "Lỗi xử lý AI." });
    } finally {
      setIsProcessing(false);
    }
  };

  const handleClearAll = () => {
    setRawText("");
    setProcessedText("");
    setStatus({ type: 'ready', msg: 'Đã xóa toàn bộ dữ liệu.' });
  };

  const copyToClipboard = () => {
    if (!processedText) return;
    navigator.clipboard.writeText(processedText);
    const oldMsg = status.msg;
    setStatus({ type: 'success', msg: "Đã sao chép vào bộ nhớ tạm!" });
    setTimeout(() => setStatus(prev => ({ ...prev, msg: oldMsg })), 2000);
  };

  return (
    <div className="h-screen flex flex-col p-4 md:p-6 lg:p-10 w-full overflow-hidden">

      {/* Header */}
      <header className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-500/20 rounded-2xl border border-blue-400/30 shadow-lg">
            <svg className="w-8 h-8 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </div>
          <div>
            <h1 className="text-2xl lg:text-3xl font-extrabold tracking-tight">
              TEX<span className="gradient-text">REWRITER</span>
            </h1>
            <p className="text-[11px] font-bold uppercase tracking-[0.2em] text-blue-400/70">
              AI-Powered LaTeX to Text
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
            className="p-3 glass-card rounded-xl hover:bg-white/10 transition-all active:scale-95"
          >
            {theme === 'dark' ? (
              <svg className="w-5 h-5 text-yellow-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 3v1m0 16v1m9-9h-1M4 9H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707M16.071 16.071l.707.707M7.929 7.929l.707-.707M12 8a4 4 0 100 8 4 4 0 000-8z" /></svg>
            ) : (
              <svg className="w-5 h-5 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" /></svg>
            )}
          </button>
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="px-6 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl text-sm font-bold flex items-center gap-2 transition-all shadow-xl shadow-blue-500/20 active:scale-95"
            disabled={isProcessing}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
            TẢI TỆP .TEX
          </button>
          <input type="file" ref={fileInputRef} className="hidden" multiple accept=".tex" onChange={handleFileUpload} />
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-0 mb-8">

        {/* Input Pane */}
        <div className="flex flex-col glass-card rounded-3xl overflow-hidden relative">
          <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
            <h2 className="text-[12px] font-bold uppercase tracking-widest text-blue-400">Nội dung LaTeX gốc</h2>
            <button 
              onClick={handleClearAll} 
              className="text-red-400 hover:text-red-300 text-[11px] font-bold flex items-center gap-1 transition-colors"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
              XÓA TẤT CẢ
            </button>
          </div>
          <textarea
            className="flex-1 w-full bg-transparent p-6 text-sm lg:text-base monospace resize-none focus:outline-none custom-scrollbar placeholder:opacity-30 text-inherit"
            value={rawText}
            onChange={(e) => setRawText(e.target.value)}
            placeholder="Dán mã LaTeX vào đây hoặc chọn tệp..."
            disabled={isProcessing}
          />
        </div>

        {/* Output Pane */}
        <div className="flex flex-col glass-card rounded-3xl overflow-hidden bg-blue-900/10">
          <div className="flex items-center justify-between px-6 py-4 border-b border-white/10 bg-white/5">
            <h2 className="text-[12px] font-bold uppercase tracking-widest text-emerald-400">Văn bản đã chuyển đổi</h2>
            <button 
              onClick={copyToClipboard}
              disabled={!processedText}
              className="px-4 py-1.5 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-30 text-white rounded-lg text-[10px] font-bold uppercase tracking-widest transition-all"
            >
              SAO CHÉP
            </button>
          </div>
          <textarea
            readOnly
            className="flex-1 w-full bg-transparent p-6 text-sm lg:text-base resize-none focus:outline-none custom-scrollbar placeholder:opacity-30 leading-relaxed text-inherit"
            value={processedText}
            placeholder="Kết quả AI viết lại sẽ xuất hiện ở đây..."
          />
        </div>
      </main>

      {/* Footer / Controls */}
      <footer className="glass-card p-6 rounded-3xl flex flex-col md:flex-row items-center justify-between gap-6 border-blue-500/20">
        <div className="flex items-center gap-4">
          {isProcessing ? (
            <div className="loader w-6 h-6 border-4 border-blue-400 border-t-transparent rounded-full"></div>
          ) : (
            <div className={`w-3 h-3 rounded-full ${status.type === 'error' ? 'bg-red-500 shadow-[0_0_12px_#ef4444]' : 'bg-blue-500 shadow-[0_0_12px_#3b82f6]'}`}></div>
          )}
          <span className={`text-[12px] font-bold uppercase tracking-widest ${status.type === 'error' ? 'text-red-400' : 'text-blue-200'}`}>
            {status.msg}
          </span>
        </div>

        <button 
          onClick={handleRewrite}
          disabled={isProcessing || !rawText.trim()}
          className="w-full md:w-auto px-10 py-4 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white rounded-2xl font-black text-sm tracking-widest shadow-2xl shadow-blue-500/30 transition-all active:scale-95 disabled:opacity-50 disabled:pointer-events-none"
        >
          VIẾT LẠI VỚI AI GEMINI
        </button>
      </footer>
    </div>
  );
};

export default App;

